import dspy

class IntentClassifier(dspy.Signature):
    '''Classify user intent for routing.'''
    user_query = dspy.InputField()
    intent_category = dspy.OutputField(desc='one of: sales, support, medical, billing')

class IntentModule(dspy.Module):
    def __init__(self):
        super().__init__()
        self.classify = dspy.ChainOfThought(IntentClassifier)

    def forward(self, user_query: str) -> dict:
        return self.classify(user_query=user_query)

class RAGGenerator(dspy.Signature):
    '''Answer using provided context.'''
    context = dspy.InputField(desc='relevant docs')
    question = dspy.InputField()
    answer = dspy.OutputField(desc='concise, accurate response')

class RAGModule(dspy.Module):
    def __init__(self):
        super().__init__()
        self.generate = dspy.ChainOfThought(RAGGenerator)

    def forward(self, context: str, question: str) -> dict:
        return self.generate(context=context, question=question)

class ConversationManager(dspy.Module):
    def __init__(self, max_turns=5):
        super().__init__()
        self.max_turns = max_turns
        self.history = []

    def forward(self, user_input: str, bot_response: str) -> str:
        self.history.append({'user': user_input, 'bot': bot_response})
        context = '\n'.join([f'U: {t["user"]}\nA: {t["bot"]}' 
                            for t in self.history[-self.max_turns:]])
        return context

    def get_context(self) -> str:
        return self.history[-3:] if self.history else ''

class AIChatbot(dspy.Module):
    def __init__(self):
        super().__init__()
        self.intent = IntentModule()
        self.rag = RAGModule()
        self.memory = ConversationManager()

    def forward(self, user_query: str, retrieved_docs: str = '') -> dict:
        # Classify intent
        intent = self.intent(user_query)

        # Generate with context
        context = retrieved_docs or self.memory.get_context()
        response = self.rag(context=context, question=user_query)

        # Update memory
        self.memory(user_query, response['answer'])

        return {'intent': intent['intent_category'], 
                'response': response['answer']}

