import vex

class VerifiedIntentModule(dspy.Module):
    def __init__(self):
        super().__init__()
        self.classify = dspy.ChainOfThought(IntentClassifier)

    def forward(self, user_query: str) -> dict:
        raw_output = self.classify(user_query=user_query)

        # Vex verification
        verified = vex.verify(
            model_output=raw_output,
            assertions=[
                vex.Assertion(
                    name='valid_intent',
                    metric=vex.Metric.CATEGORICAL,
                    reference=['sales', 'support', 'medical', 'billing'],
                    field='intent_category',
                    threshold=1.0
                )
            ],
            risk_profile='high'
        )
        return verified.output if verified.passed else {'error': 'Invalid intent'}
